components.codeTemplate:
BarMark(
    x: .value("Category", item.category),
    y: .value("Value", item.value),
    width: {barWidth},
    stacking: {stacking}
)
.cornerRadius({cornerRadius})
.foregroundStyle({foregroundStyle})
.opacity({opacity})
.annotation(position: {annotationPosition}) {
    Text(item.value, format: .number)
        .font(.caption2)
}

RuleMark(
    y: .value("Threshold", threshold)
)
.lineStyle(StrokeStyle(lineWidth: {lineWidth}, dash: {dashed} ? [4, 4] : []))
.foregroundStyle({foregroundStyle})
.annotation(position: {annotationPosition}, alignment: .leading) {
    Text("Goal")
        .font(.caption2)
        .foregroundStyle({foregroundStyle})
}

RectangleMark(
    x: .value("Column", item.column),
    y: .value("Row", item.row),
    width: {cellWidth},
    height: {cellHeight}
)
.foregroundStyle(by: .value("Value", item.value))
.opacity({opacity})
// Pair with:
// .chartForegroundStyleScale(range: Gradient(colors: [.white, {valueColor}]))

Chart {
    BarPlot(
        data,
        x: .value("Category", {xKeyPath}),
        y: .value("Value", {yKeyPath})
    )
    .foregroundStyle({foregroundStyle})
}

Chart {
    LinePlot(x: "x", y: "y") { x in
        x * x
    }
    .lineStyle(StrokeStyle(lineWidth: {lineWidth}, lineCap: {lineCap}))
    .foregroundStyle({foregroundStyle})
    .opacity({opacity})
}
.chartXScale(domain: -10 ... 10)
.chartYScale(domain: -10 ... 10)

Chart {
    AreaPlot(x: "x", y: "y") { x in
        sin(x)
    }
    .foregroundStyle({useGradient} ? AnyShapeStyle(LinearGradient(colors: [{foregroundStyle}, .clear], startPoint: .top, endPoint: .bottom)) : AnyShapeStyle({foregroundStyle}))
    .opacity({opacity})
}
.chartXScale(domain: -10 ... 10)
.chartYScale(domain: -2 ... 2)

Chart {
    PointPlot(
        data,
        x: .value("X", {xKeyPath}),
        y: .value("Y", {yKeyPath})
    )
    .symbolSize({symbolSize})
    .foregroundStyle({foregroundStyle})
    .opacity({opacity})
}

Chart {
    SectorPlot(
        data,
        angle: .value("Value", {angleKeyPath}),
        innerRadius: .ratio({innerRadiusRatio}),
        angularInset: {angularInset}
    )
    .foregroundStyle(by: .value("Category", {foregroundStyleKeyPath}))
}

Chart {
    RulePlot(
        data,
        x: .value("X", \.x)
    )
    .lineStyle(StrokeStyle(lineWidth: {lineWidth}))
    .foregroundStyle({foregroundStyle})
    .opacity({opacity})
}

Chart3D {
    SurfacePlot(x: "x", y: "y", z: "z") { x, z in
        sin(x) * cos(z)
    }
}
.chart3DCameraProjection({cameraProjection})
.chart3DPose({pose})

.chartYAxis {
    AxisMarks(
        position: {axisPosition},
        values: .automatic(desiredCount: {desiredTickCount})
    ) { value in
        if {showGridLines} { AxisGridLine() }
        if {showTicks} { AxisTick() }
        if {showValueLabels} {
            AxisValueLabel(orientation: {labelOrientation})
        }
    }
}

.chartYScale(
    domain: {useFixedDomain} ? {domainLowerBound} ... {domainUpperBound} : .automatic,
    type: {scaleType}
)

.chartForegroundStyleScale(
    range: {scaleMode} == .continuous
        ? AnyShapeStyle(Gradient(colors: [{paletteColor1}, {paletteColor2}]))
        : AnyShapeStyle({paletteColor1})
)
// Marks use: .foregroundStyle(by: .value("Category", item.group))

Chart {
    ForEach(data) { item in
        BarMark(x: .value("Date", item.date), y: .value("Value", item.value))
            .foregroundStyle(item.date == selectedDate ? Color.accentColor : Color.gray)
    }
    if let selectedDate {
        RuleMark(x: .value("Selected", selectedDate))
            .annotation(position: .top, overflowResolution: .init(x: {annotationOverflow}, y: .fit)) {
                Text("\(selectedValue)")
            }
    }
}
.chartXSelection(value: $selectedDate)
.chartScrollableAxes({scrollableAxes})
.chartXVisibleDomain(length: {visibleDomainLength})

Chart3D {
    SurfacePlot(x: "x", y: "y", z: "z") { x, z in
        sin(2 * x) * cos(2 * z)
    }
    .foregroundStyle({surfaceStyle})
}
.chartXScale(domain: -{xDomainLength} ... {xDomainLength})
.chartYScale(domain: -1 ... 1)
.chartZScale(domain: -{zDomainLength} ... {zDomainLength})

Chart(data) { item in
    LineMark(x: .value("Date", item.date), y: .value("Value", item.value))
}
.chartOverlay { proxy in
    GeometryReader { geo in
        Rectangle().fill(.clear).contentShape(Rectangle())
            .gesture(DragGesture().onChanged { value in
                let origin = geo[proxy.plotAreaFrame].origin
                if let date: Date = proxy.value(atX: value.location.x - origin.x) {
                    selectedDate = date
                }
            })
        if {showCrosshair}, let selectedDate, let x = proxy.position(forX: selectedDate) {
            Rectangle()
                .fill({accentColor})
                .frame(width: 1)
                .offset(x: x + geo[proxy.plotAreaFrame].origin.x)
        }
    }
}
